'use client';

import { Link } from '@tanstack/react-router';
import { useMemo, useState } from 'react';
import { DataStateNotice } from '@/app/_components/DataStateNotice';
import { buttonVariants } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Progress } from '@/components/ui/progress';
import type { StationSnapshot } from '@/lib/api-types';
import { resolveDataState } from '@/lib/data-state';
import {
  buildStationDistrictMap,
  fetchDistrictCollection,
  type DistrictCollection,
} from '@/lib/districts';
import { appRoutes } from '@/lib/routes';
import { captureExceptionWithContext } from '@/lib/sentry-reporting';
import { useAbortableAsyncEffect } from './useAbortableAsyncEffect';

type HourlySignalRow = {
  stationId: string;
  hour: number;
  departures: number;
  arrivals: number;
  sampleCount: number;
};

type FlowPreviewPanelProps = {
  stations: StationSnapshot[];
  hourlySignals: HourlySignalRow[];
};

type RouteRow = {
  origin: string;
  destination: string;
  flow: number;
};

export function FlowPreviewPanel({ stations, hourlySignals }: FlowPreviewPanelProps) {
  const [districts, setDistricts] = useState<DistrictCollection | null>(null);
  const [isLoadingDistricts, setIsLoadingDistricts] = useState(true);
  const [districtError, setDistrictError] = useState<string | null>(null);

  useAbortableAsyncEffect(
    async (signal, isActive) => {
      const payload = await fetchDistrictCollection(signal);

      if (!payload || !isActive()) {
        return;
      }

      setDistricts(payload);
    },
    [],
    {
      onStart: () => {
        setIsLoadingDistricts(true);
        setDistrictError(null);
      },
      onError: (error) => {
        captureExceptionWithContext(error, {
          area: 'dashboard.flow-preview',
          operation: 'loadDistricts',
        });
        console.error('[Dashboard] No se pudo cargar distritos para preview de flujo.', error);
        setDistrictError('No se pudieron cargar los distritos para el resumen de flujo.');
      },
      onSettled: () => {
        setIsLoadingDistricts(false);
      },
    }
  );

  const stationDistrictMap = useMemo(() => {
    if (!districts) {
      return new Map<string, string>();
    }

    return buildStationDistrictMap(stations, districts);
  }, [districts, stations]);

  const topRoutes = useMemo<RouteRow[]>(() => {
    if (hourlySignals.length === 0 || stationDistrictMap.size === 0) {
      return [];
    }

    const districtTotals = new Map<string, { outbound: number; inbound: number }>();

    for (const row of hourlySignals) {
      const district = stationDistrictMap.get(row.stationId);

      if (!district) {
        continue;
      }

      const current = districtTotals.get(district) ?? { outbound: 0, inbound: 0 };
      current.outbound += Math.max(0, Number(row.departures));
      current.inbound += Math.max(0, Number(row.arrivals));
      districtTotals.set(district, current);
    }

    const totalInbound = Array.from(districtTotals.values()).reduce(
      (sum, row) => sum + row.inbound,
      0
    );

    if (totalInbound <= 0) {
      return [];
    }

    const routeRows: RouteRow[] = [];

    for (const [originDistrict, values] of districtTotals.entries()) {
      if (values.outbound <= 0) {
        continue;
      }

      for (const [destinationDistrict, destinationValues] of districtTotals.entries()) {
        if (originDistrict === destinationDistrict || destinationValues.inbound <= 0) {
          continue;
        }

        routeRows.push({
          origin: originDistrict,
          destination: destinationDistrict,
          flow: values.outbound * (destinationValues.inbound / totalInbound),
        });
      }
    }

    return routeRows.sort((left, right) => right.flow - left.flow).slice(0, 4);
  }, [hourlySignals, stationDistrictMap]);

  const topFlowValue = Math.max(1, ...topRoutes.map((route) => route.flow));
  const flowPreviewState = resolveDataState({
    isLoading: isLoadingDistricts,
    error: districtError,
    hasCoverage: hourlySignals.length > 0,
    hasData: topRoutes.length > 0,
  });
  const canRenderRoutes = flowPreviewState === 'ok';

  return (
    <div className="grid grid-cols-1 gap-8 p-6 lg:grid-cols-2">
      <Card className="relative h-64 items-center justify-center rounded-xl border-dashed border-[var(--primary)]/35 bg-[var(--secondary)] p-0">
        <div className="absolute inset-0 opacity-20" style={{ backgroundImage: 'radial-gradient(circle at center, #ea0615 0%, transparent 70%)' }} />
        <div className="relative z-10 flex flex-col items-center text-center">
          <span className="text-4xl text-[var(--primary)]">◎</span>
          <p className="mt-2 text-sm font-bold text-[var(--foreground)]">Modelo de distribucion espacial</p>
          <p className="mt-1 max-w-sm text-xs text-[var(--muted)]">
            Vista simplificada de la distribucion de trayectos entre los principales barrios.
          </p>
          <Link
            href={appRoutes.dashboardFlow()}
            className={buttonVariants({
              variant: 'default',
              size: 'sm',
              className: 'mt-4 min-h-0 bg-[#8f1018] px-4 py-2 text-xs font-bold hover:bg-[#731017]',
            })}
          >
            Expandir vista completa
          </Link>
        </div>
      </Card>

      <div className="space-y-3">
        <div className="flex items-start justify-between gap-3">
          <div>
            <h3 className="text-xs font-bold uppercase tracking-[0.14em] text-[var(--muted)]">
              Corredores de alto volumen
            </h3>
            <p className="mt-1 text-xs text-[var(--muted)]">
              Rutas probables entre barrios estimadas a partir de entradas y salidas agregadas.
            </p>
          </div>
          <Link
            href={appRoutes.dashboardHelp('calculo-rutas')}
            className={buttonVariants({
              variant: 'ghost',
              size: 'sm',
              className: 'min-h-0 px-1 py-0 text-xs font-semibold text-[var(--primary)] hover:underline',
            })}
          >
            Como se calcula
          </Link>
        </div>

        {!canRenderRoutes ? (
          <DataStateNotice
            state={flowPreviewState}
            subject="el resumen de flujo"
            description={
              districtError ??
              (isLoadingDistricts
                ? 'Estamos cargando la geometria de barrios para estimar corredores.'
                : 'No hay suficientes señales horarias para estimar corredores en esta ventana.')
            }
            href={appRoutes.status()}
            actionLabel="Ver estado"
            compact
          />
        ) : (
          topRoutes.map((route) => {
            const flowPct = Math.max(8, Math.round((route.flow / topFlowValue) * 100));

            return (
              <Card
                variant="stat"
                key={`${route.origin}-${route.destination}`}
                className="gap-2 rounded-lg p-3"
              >
                <div className="mb-1 flex items-center justify-between gap-2">
                  <p className="text-sm font-bold text-[var(--foreground)]">
                    {route.origin} → {route.destination}
                  </p>
                  <p className="text-xs font-bold text-[var(--foreground)]">{route.flow.toFixed(0)}</p>
                </div>
                <Progress className="bg-black/25" value={flowPct} indicatorClassName="bg-[var(--primary)]" />
              </Card>
            );
          })
        )}
      </div>
    </div>
  );
}
