'use client';

import { Suspense } from 'react';
import { Link } from '@tanstack/react-router';
import { useLocation, useRouter, useSearch } from '@tanstack/react-router';
import { useMemo } from 'react';
import { DataStateNotice } from '@/app/_components/DataStateNotice';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Progress } from '@/components/ui/progress';
import { Skeleton } from '@/components/ui/skeleton';
import type { RankingsResponse, StationSnapshot } from '@/lib/api-types';
import { resolveDataState } from '@/lib/data-state';
import { appRoutes } from '@/lib/routes';
import { InfoHint } from './InfoHint';
import { formatPercent } from '@/lib/format';
import { calculateFrictionScore } from './useSystemMetrics';

type RankingsTableProps = {
  rankings: {
    turnover: RankingsResponse;
    availability: RankingsResponse;
  };
  stations: StationSnapshot[];
  density?: 'normal' | 'compact';
};

type RankingTab = 'turnover' | 'availability';

function RankingsTableContent({ rankings, stations, density = 'normal' }: RankingsTableProps) {
  const router = useRouter();
  const location = useLocation();
  const pathname = location.pathname;
  const searchParams = new URLSearchParams((location as { searchStr?: string }).searchStr ?? '');
  const tabFromUrl = searchParams.get('rankingTab');
  const activeTab: RankingTab =
    tabFromUrl === 'turnover' ? 'turnover' : 'availability';
  const search = searchParams.get('rankingSearch') ?? '';
  const showAll = searchParams.get('rankingShowAll') === '1';

  const updateQuery = (next: { tab?: RankingTab; search?: string; showAll?: boolean }) => {
    const nextParams = new URLSearchParams(searchParams.toString());
    const nextTab = next.tab ?? activeTab;
    const nextSearch = next.search ?? search;
    const nextShowAll = next.showAll ?? showAll;

    nextParams.set('rankingTab', nextTab);

    if (nextSearch.trim()) {
      nextParams.set('rankingSearch', nextSearch.trim());
    } else {
      nextParams.delete('rankingSearch');
    }

    if (nextShowAll) {
      nextParams.set('rankingShowAll', '1');
    } else {
      nextParams.delete('rankingShowAll');
    }

    const nextQuery = nextParams.toString();
    router.navigate({ to: nextQuery ? `${pathname}?${nextQuery}` : pathname, replace: true });
  };

  const stationMap = useMemo(() => {
    return new Map(stations.map((station) => [station.id, station]));
  }, [stations]);

  const rows = useMemo(() => {
    const activeRankings = rankings[activeTab]?.rankings ?? [];
    const normalizedSearch = search.trim().toLowerCase();

    const enriched = activeRankings.map((row) => {
      const station = stationMap.get(row.stationId);
      const problemHours = calculateFrictionScore(row.emptyHours, row.fullHours);
      const problemRate = row.totalHours > 0 ? (problemHours / row.totalHours) * 100 : 0;

      return {
        ...row,
        stationName: station?.name ?? row.stationId,
        stationCapacity: station?.capacity ?? 0,
        problemHours,
        problemRate,
      };
    });

    const filtered = normalizedSearch
      ? enriched.filter((row) => {
          const name = row.stationName.toLowerCase();
          const id = row.stationId.toLowerCase();
          return name.includes(normalizedSearch) || id.includes(normalizedSearch);
        })
      : enriched;

    if (activeTab === 'turnover') {
      return filtered.sort((left, right) => right.turnoverScore - left.turnoverScore);
    }

    return filtered.sort((left, right) => right.problemHours - left.problemHours);
  }, [activeTab, rankings, search, stationMap]);

  const visibleRows = showAll ? rows : rows.slice(0, 8);

  const maxTurnover = Math.max(1, ...rows.map((row) => row.turnoverScore));
  const maxProblemRate = Math.max(1, ...rows.map((row) => row.problemRate));
  const activeRankings = rankings[activeTab];
  const rankingsState = search.trim()
    ? resolveDataState({
        hasCoverage: activeRankings.dataState !== 'no_coverage',
        hasData: visibleRows.length > 0,
      })
    : activeRankings.dataState;
  const canRenderRows =
    rankingsState === 'ok' ||
    rankingsState === 'partial' ||
    rankingsState === 'stale';
  const itemClass =
    density === 'compact'
      ? 'rounded-lg border border-[var(--border)] bg-[var(--secondary)]/90 px-3 py-2'
      : 'rounded-lg border border-[var(--border)] bg-[var(--secondary)]/90 px-3 py-2.5';

  return (
    <section className='ui-section-card h-full'>
      <header className='flex items-center justify-between gap-2'>
        <div>
          <h2 className='text-sm font-bold uppercase tracking-[0.12em] text-[var(--foreground)]'>
            Cuellos de botella
          </h2>
          <div className='mt-1 flex items-center gap-2'>
            <p className='text-xs text-[var(--muted)]'>Estaciones con mayor friccion operativa recurrente.</p>
            <InfoHint
              label='Como se calcula la friccion'
              content='La friccion suma el tiempo en que una estacion estuvo vacia o llena. Cuantas mas horas problema acumula, mas alta aparece en el ranking.'
            />
          </div>
        </div>
        <div className='text-right'>
          <span className='ui-chip'>{rows.length} resultados</span>
          <div className='mt-1'>
            <Link
              href={appRoutes.dashboardHelp('ranking-rotacion-vs-criticidad')}
              className='text-xs font-semibold text-[var(--primary)] underline-offset-2 hover:underline'
            >
              Entender ranking
            </Link>
          </div>
        </div>
      </header>

      <div className='flex flex-wrap items-center gap-2'>
        <div className='flex gap-2'>
          <Button
            variant={activeTab === 'availability' ? 'default' : 'outline'}
            className={`rounded-full h-auto min-h-0 ${
              activeTab === 'availability'
                ? ''
                : ''
            }`}
            onClick={() => {
              updateQuery({ tab: 'availability', showAll: false });
            }}
          >
            Criticas
          </Button>
          <Button
            variant={activeTab === 'turnover' ? 'default' : 'outline'}
            className={`rounded-full h-auto min-h-0 ${
              activeTab === 'turnover'
                ? ''
                : ''
            }`}
            onClick={() => {
              updateQuery({ tab: 'turnover', showAll: false });
            }}
          >
            Rotacion
          </Button>
        </div>

        <Input
          className='h-8 min-h-0 min-w-[180px] flex-1 rounded-lg border border-[var(--border)] bg-[var(--secondary)] px-3 py-1.5 text-xs text-[var(--foreground)] outline-none placeholder:text-[var(--muted)]'
          placeholder='Buscar estacion'
          value={search}
          onChange={(event) => {
            updateQuery({ search: event.target.value, showAll: false });
          }}
        />
      </div>

      {rankingsState === 'partial' || rankingsState === 'stale' ? (
        <DataStateNotice
          state={rankingsState}
          subject={`el ranking de ${activeTab === 'turnover' ? 'rotacion' : 'criticidad'}`}
          description={
            rankingsState === 'partial'
              ? 'El ranking tiene datos utiles, pero la cobertura disponible no llena toda la ventana ideal.'
              : 'El ranking se ha calculado con datos antiguos y puede no reflejar el estado actual.'
          }
          href={appRoutes.status()}
          actionLabel='Ver estado'
          className='mb-3'
          compact
        />
      ) : null}

      {!canRenderRows ? (
        <DataStateNotice
          state={rankingsState}
          subject={`el ranking de ${activeTab === 'turnover' ? 'rotacion' : 'criticidad'}`}
          description={
            search.trim()
              ? 'No hay estaciones que coincidan con la busqueda actual.'
              : 'Todavia no hay datos suficientes para calcular este ranking.'
          }
          href={appRoutes.status()}
          actionLabel='Ver estado'
          compact
        />
      ) : (
        <ul className='space-y-2'>
          {visibleRows.map((row) => {
            const barWidth =
              activeTab === 'turnover'
                ? (row.turnoverScore / maxTurnover) * 100
                : (row.problemRate / maxProblemRate) * 100;

            return (
              <li
                key={`${row.id}-${activeTab}`}
                className={itemClass}
              >
                <div className='mb-1 flex items-center justify-between gap-2'>
                  <div>
                    <p className='text-sm font-semibold text-[var(--foreground)]'>{row.stationName}</p>
                    <p className='text-[10px] uppercase tracking-[0.12em] text-[var(--muted)]'>
                      {row.stationId}
                    </p>
                  </div>

                  {activeTab === 'turnover' ? (
                    <p className='text-xs font-bold text-[var(--foreground)]'>
                      {row.turnoverScore.toFixed(1)}x
                    </p>
                  ) : (
                    <p className='text-xs font-bold text-[var(--foreground)]'>
                      {row.problemHours}h · {formatPercent(row.problemRate)}
                    </p>
                  )}
                </div>

                <Progress
                  className='bg-black/25'
                  value={Math.max(8, Math.min(100, barWidth))}
                  indicatorClassName={activeTab === 'turnover' ? 'bg-[var(--primary)]' : 'bg-amber-400'}
                />
                <p className='mt-2 text-[11px] text-[var(--muted)]'>
                  {activeTab === 'turnover'
                    ? `Movimiento relativo frente al resto de estaciones. Capacidad ${row.stationCapacity}.`
                    : `Friccion = horas vacia + horas llena sobre ${row.totalHours}h observadas.`}
                </p>
              </li>
            );
          })}
        </ul>
      )}

      {rows.length > 8 ? (
        <Button
          variant="cta"
          onClick={() => {
            updateQuery({ showAll: !showAll });
          }}
          className="h-auto min-h-0 rounded-lg px-3 py-1.5 text-xs font-bold"
        >
          {showAll ? 'Mostrar menos' : 'Ver mas'}
        </Button>
      ) : null}
    </section>
  );
}

export function RankingsTable(props: RankingsTableProps) {
  return (
    <Suspense fallback={<div className='ui-section-card h-full'><Skeleton className="h-24 w-full" /></div>}>
      <RankingsTableContent {...props} />
    </Suspense>
  );
}
